select

from tb_todo


    and user_id = #{userId,jdbcType=BIGINT}


    and title like concat('%', #{title}, '%')


    and content between #{content} and #{content}


    and category_id = #{categoryId,jdbcType=BIGINT}


    and priority = #{priority,jdbcType=TINYINT}


    and end_time >= #{startTime.start}


    and start_time <= #{endTime.end}


    and status = #{status,jdbcType=TINYINT}


    and finish_time between #{finishTime.start} and #{finishTime.end}


    and is_delete = #{isDelete,jdbcType=TINYINT}


    and is_top = #{isTop,jdbcType=TINYINT}


order by create_time desc

select count(*)
from tb_todo


    and user_id = #{userId,jdbcType=BIGINT}


    and title like concat('%', #{title}, '%')


    and content between #{content} and #{content}


